mapper.select:
SELECT p.post_id AS id, p.board_id AS "boardId", p.title, u.user_name AS "authorName", p.view_count AS "viewCount", p.created_date AS "createdAt", p.modified_date AS "updatedAt" FROM tb_post p LEFT JOIN tb_user u ON u.user_id = p.created_by WHERE p.board_id = #{boardId}
AND p.title LIKE '%' || #{search} || '%'
AND u.user_name LIKE '%' || #{search} || '%'
AND (p.title LIKE '%' || #{search} || '%' OR u.user_name LIKE '%' || #{search} || '%')
ORDER BY p.created_date ${sortOrder} LIMIT #{limit} OFFSET #{offset}
